// 食物类
class Food {
    constructor(canvas, snake) {
        this.canvas = canvas;
        this.snake = snake;
        this.size = 20;
        this.color = '#ff4757';
        this.position = this.generatePosition();
    }

    generatePosition() {
        let position;
        let valid = false;
        while (!valid) {
            position = {
                x: Math.floor(Math.random() * (this.canvas.width / this.size)) * this.size,
                y: Math.floor(Math.random() * (this.canvas.height / this.size)) * this.size
            };
            // 确保食物不会生成在蛇身上
            valid = !this.snake.body.some(segment => 
                segment.x === position.x && segment.y === position.y
            );
        }
        return position;
    }

    draw(ctx) {
        // 绘制圆形食物
        ctx.fillStyle = this.color;
        ctx.beginPath();
        ctx.arc(
            this.position.x + this.size / 2,
            this.position.y + this.size / 2,
            this.size / 2 - 2,
            0,
            Math.PI * 2
        );
        ctx.fill();

        // 添加阴影效果
        ctx.shadowColor = this.color;
        ctx.shadowBlur = 10;
        ctx.shadowBlur = 0; // 重置阴影
    }
}

// 蛇类
class Snake {
    constructor(canvas) {
        this.canvas = canvas;
        this.size = 20;
        this.speed = 150; // 毫秒
        this.direction = 'RIGHT';
        this.nextDirection = 'RIGHT';
        this.body = [
            { x: 100, y: 100 },
            { x: 80, y: 100 },
            { x: 60, y: 100 }
        ];
        this.growPending = 0;
    }

    get head() {
        return this.body[0];
    }

    changeDirection(newDirection) {
        // 防止反向移动
        const opposites = {
            'UP': 'DOWN',
            'DOWN': 'UP',
            'LEFT': 'RIGHT',
            'RIGHT': 'LEFT'
        };
        if (opposites[newDirection] !== this.direction) {
            this.nextDirection = newDirection;
        }
    }

    move() {
        this.direction = this.nextDirection;

        const newHead = { ...this.head };

        switch (this.direction) {
            case 'UP': newHead.y -= this.size; break;
            case 'DOWN': newHead.y += this.size; break;
            case 'LEFT': newHead.x -= this.size; break;
            case 'RIGHT': newHead.x += this.size; break;
        }

        this.body.unshift(newHead);

        if (this.growPending > 0) {
            this.growPending--;
        } else {
            this.body.pop();
        }
    }

    checkCollision() {
        // 检查墙壁碰撞
        if (this.head.x < 0 || this.head.x >= this.canvas.width ||
            this.head.y < 0 || this.head.y >= this.canvas.height) {
            return true;
        }

        // 检查自身碰撞
        for (let i = 1; i < this.body.length; i++) {
            if (this.head.x === this.body[i].x && this.head.y === this.body[i].y) {
                return true;
            }
        }

        return false;
    }

    grow() {
        this.growPending++;
    }

    draw(ctx) {
        this.body.forEach((segment, index) => {
            // 蛇头颜色不同
            ctx.fillStyle = index === 0 ? '#2ed573' : '#7bed9f';

            // 绘制圆角矩形
            const x = segment.x;
            const y = segment.y;
            const size = this.size;

            ctx.fillRect(x, y, size, size);

            // 绘制边框
            ctx.strokeStyle = '#2f3542';
            ctx.lineWidth = 1;
            ctx.strokeRect(x, y, size, size);

            // 绘制蛇头眼睛
            if (index === 0) {
                ctx.fillStyle = '#2f3542';
                const eyeSize = 4;
                let eyeX1, eyeY1, eyeX2, eyeY2;

                switch (this.direction) {
                    case 'UP':
                        eyeX1 = x + 5; eyeY1 = y + 5;
                        eyeX2 = x + 15; eyeY2 = y + 5;
                        break;
                    case 'DOWN':
                        eyeX1 = x + 5; eyeY1 = y + 15;
                        eyeX2 = x + 15; eyeY2 = y + 15;
                        break;
                    case 'LEFT':
                        eyeX1 = x + 5; eyeY1 = y + 5;
                        eyeX2 = x + 5; eyeY2 = y + 15;
                        break;
                    case 'RIGHT':
                        eyeX1 = x + 15; eyeY1 = y + 5;
                        eyeX2 = x + 15; eyeY2 = y + 15;
                        break;
                }

                ctx.fillRect(eyeX1, eyeY1, eyeSize, eyeSize);
                ctx.fillRect(eyeX2, eyeY2, eyeSize, eyeSize);
            }
        });
    }
}

// 游戏主类
class Game {
    constructor() {
        this.canvas = document.getElementById('game-canvas');
        this.ctx = this.canvas.getContext('2d');

        this.snake = new Snake(this.canvas);
        this.food = new Food(this.canvas, this.snake);

        this.score = 0;
        this.highScore = localStorage.getItem('snakeHighScore') || 0;
        this.gameSpeed = 150;
        this.gameInterval = null;
        this.isPaused = false;
        this.isGameOver = false;
        this.isRunning = false;

        this.initUI();
        this.bindEvents();
        this.draw();
    }

    initUI() {
        document.getElementById('high-score').textContent = this.highScore;
    }

    bindEvents() {
        // 键盘控制
        document.addEventListener('keydown', (e) => {
            if (!this.isRunning || this.isPaused) return;

            switch (e.key) {
                case 'ArrowUp': this.snake.changeDirection('UP'); break;
                case 'ArrowDown': this.snake.changeDirection('DOWN'); break;
                case 'ArrowLeft': this.snake.changeDirection('LEFT'); break;
                case 'ArrowRight': this.snake.changeDirection('RIGHT'); break;
                case ' ': this.togglePause(); break;
            }
        });

        // 按钮控制
        document.getElementById('start-btn').addEventListener('click', () => this.start());
        document.getElementById('pause-btn').addEventListener('click', () => this.togglePause());
        document.getElementById('reset-btn').addEventListener('click', () => this.reset());
        document.getElementById('restart-btn').addEventListener('click', () => this.reset());
    }

    start() {
        if (this.isRunning) return;

        this.isRunning = true;
        this.isPaused = false;
        this.isGameOver = false;

        document.getElementById('start-btn').style.display = 'none';
        document.getElementById('pause-btn').innerHTML = '<i class="fas fa-pause"></i> 暂停';

        this.gameLoop();
    }

    gameLoop() {
        if (this.gameInterval) clearInterval(this.gameInterval);

        this.gameInterval = setInterval(() => {
            if (!this.isPaused && this.isRunning && !this.isGameOver) {
                this.update();
                this.draw();
            }
        }, this.gameSpeed);
    }

    update() {
        this.snake.move();

        // 检查碰撞
        if (this.snake.checkCollision()) {
            this.gameOver();
            return;
        }

        // 检查是否吃到食物
        if (this.snake.head.x === this.food.position.x && 
            this.snake.head.y === this.food.position.y) {
            this.snake.grow();
            this.food = new Food(this.canvas, this.snake);
            this.score += 10;
            this.updateScore();

            // 随着分数增加，游戏速度加快
            if (this.score % 50 === 0 && this.gameSpeed > 50) {
                this.gameSpeed -= 5;
                this.gameLoop();
            }
        }
    }

    draw() {
        // 清空画布
        this.ctx.fillStyle = '#2f3542';
        this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

        // 绘制网格
        this.ctx.strokeStyle = '#57606f';
        this.ctx.lineWidth = 0.5;
        for (let x = 0; x <= this.canvas.width; x += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(x, 0);
            this.ctx.lineTo(x, this.canvas.height);
            this.ctx.stroke();
        }
        for (let y = 0; y <= this.canvas.height; y += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, y);
            this.ctx.lineTo(this.canvas.width, y);
            this.ctx.stroke();
        }

        // 绘制游戏元素
        this.food.draw(this.ctx);
        this.snake.draw(this.ctx);
    }

    updateScore() {
        document.getElementById('score').textContent = this.score;
        document.getElementById('length').textContent = this.snake.body.length;

        if (this.score > this.highScore) {
            this.highScore = this.score;
            localStorage.setItem('snakeHighScore', this.highScore);
            document.getElementById('high-score').textContent = this.highScore;
        }
    }

    togglePause() {
        if (!this.isRunning || this.isGameOver) return;

        this.isPaused = !this.isPaused;
        const pauseBtn = document.getElementById('pause-btn');

        if (this.isPaused) {
            pauseBtn.innerHTML = '<i class="fas fa-play"></i> 继续';
            this.ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
            this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
            this.ctx.fillStyle = '#ffffff';
            this.ctx.font = '30px Arial';
            this.ctx.textAlign = 'center';
            this.ctx.fillText('游戏暂停', this.canvas.width / 2, this.canvas.height / 2);
        } else {
            pauseBtn.innerHTML = '<i class="fas fa-pause"></i> 暂停';
        }
    }

    gameOver() {
        this.isRunning = false;
        this.isGameOver = true;
        clearInterval(this.gameInterval);

        document.getElementById('game-over').style.display = 'block';
        document.getElementById('final-score').textContent = this.score;
        document.getElementById('start-btn').style.display = 'inline-block';
        document.getElementById('pause-btn').innerHTML = '<i class="fas fa-pause"></i> 暂停';
    }

    reset() {
        this.snake = new Snake(this.canvas);
        this.food = new Food(this.canvas, this.snake);
        this.score = 0;
        this.gameSpeed = 150;
        this.isPaused = false;
        this.isGameOver = false;
        this.isRunning = false;

        this.updateScore();
        document.getElementById('game-over').style.display = 'none';
        document.getElementById('start-btn').style.display = 'inline-block';
        document.getElementById('pause-btn').innerHTML = '<i class="fas fa-pause"></i> 暂停';

        this.draw();
    }
}

