        ctx.fillStyle = this.color;
        ctx.beginPath();
        ctx.arc(
            this.position.x + this.size / 2,
            this.position.y + this.size / 2,
            this.size / 2 - 2,
            0,
            Math.PI * 2
        );
        ctx.fill();

        // 添加阴影效果
        ctx.shadowColor = this.color;
        ctx.shadowBlur = 10;
        ctx.shadowBlur = 0; // 重置阴影
    }
}

